function solve(nums: number[], queries: number[][]): number[] {
    const n = nums.length;
    const ans: number[] = [];

    // Preprocess: for each index, store the positions of each number
    const posMap = new Map<number, number[]>();
    for (let i = 0; i < n; ++i) {
        if (!posMap.has(nums[i])) {
            posMap.set(nums[i], []);
        }
        posMap.get(nums[i])!.push(i);
    }

    for (const query of queries) {
        const l = query[0], r = query[1], threshold = query[2];
        const freq = new Map<number, number>();
        let found = false;
        let result = -1;

        // Count frequency of each number in the subarray
        for (let i = l; i <= r; ++i) {
            const num = nums[i];
            if (!freq.has(num)) {
                freq.set(num, 0);
            }
            freq.set(num, freq.get(num)! + 1);
        }

        // Find the element with highest frequency (and smallest value in case of tie)
        for (const [num, count] of freq.entries()) {
            if (count >= threshold) {
                found = true;
                if (result === -1 || count > freq.get(result)! || (count === freq.get(result)! && num < result)) {
                    result = num;
                }
            }
        }

        ans.push(result);
    }

    return ans;
}
